def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    base_weights = np.array([0.5, 0.3, 0.1, 0.07, 0.03])
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-(ratio * 12)) + 0.12
        elif 0.4 < ratio <= 0.7:
            score = (1 - ratio) ** 2 + 0.2
        else:
            score = 0.0
            for k in range(1, 8):
                term = ((-1)**(k+1)) * (ratio ** (k + 2)) / (k * 1.8)
                score += term
            score = abs(score) + 0.07
        neighbors_influence = 0.0
        for offset in range(1, 6):
            weight = base_weights[offset-1] if offset-1 < len(base_weights) else 0.01
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    rel_diff = diff / max(capacity, neighbor_capacity)
                    adj = (rel_diff ** 2) * weight
                    neighbors_influence += adj
        penalty = 0.0
        for j in range(n):
            if j != i and bins[j] > 0:
                dist = abs(i - j)
                if dist < 3:
                    penalty += (item / bins[j]) ** 2 / (dist + 1)
        capacity_factor = np.log1p(capacity)
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + neighbors_influence / capacity_factor + penalty * 0.05
        for loop in range(2):
            if priority > 1.5 and ratio < 0.3:
                priority -= 0.1 * (loop + 1)
            elif priority < 0.2 and ratio > 0.8:
                priority += 0.05 * (loop + 1)
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    sum_priorities = np.sum(priorities[np.isfinite(priorities)])
    if sum_priorities > 0:
        priorities = priorities / sum_priorities
    return priorities
